const row = (Array.isArray(msg.payload) && msg.payload[0]) ? msg.payload[0] : null;
if (!row || !row.image) {
    // niente immagine
    msg.payload = null;
    return msg;
}

const buf = Buffer.from(row.image);

// Detect MIME da magic bytes (PNG / JPEG), fallback PNG
let mime = "image/png";
if (buf.length >= 3 && buf[0] === 0xFF && buf[1] === 0xD8 && buf[2] === 0xFF) mime = "image/jpeg";
if (buf.length >= 8 &&
    buf[0] === 0x89 && buf[1] === 0x50 && buf[2] === 0x4E && buf[3] === 0x47 &&
    buf[4] === 0x0D && buf[5] === 0x0A && buf[6] === 0x1A && buf[7] === 0x0A) mime = "image/png";

// Buffer -> base64 data URL
const b64 = buf.toString("base64");
msg.payload = `data:${mime};base64,${b64}`;

return msg;

