function normalizePhase(value) {
    let phase = (value || "").toString().trim().toLowerCase();

    if (phase === "in_progress" || phase === "in lavorazione" || phase === "in corso" || phase === "progress") {
        return "in progress";
    }

    if (phase === "completato" || phase === "completati" || phase === "completed") {
        return "completed";
    }

    if (phase === "creato" || phase === "creati" || phase === "created" || phase === "create") {
        return "created";
    }

    if (phase === "validato" || phase === "validati" || phase === "validated") {
        return "validated";
    }

    if (phase === "approvato" || phase === "approvati" || phase === "approved") {
        return "approved";
    }

    if (phase === "annullato" || phase === "annullati" || phase === "cancelled" || phase === "cancellato" || phase === "cancellati") {
        return "cancelled";
    }

    if (phase === "test" || phase === "testing" || phase === "in test" || phase === "verifica") {
        return "testing";
    }

    return phase;
}

