// Funzione per convertire dd/mm/yyyy -> yyyy-mm-dd
function normalizeDate(dateStr) {
    if (!dateStr) return null;

    if (/^\d{4}-\d{2}-\d{2}$/.test(dateStr)) {
        return dateStr;
    }

    const m = dateStr.match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
    if (m) {
        return `${m[3]}-${m[2]}-${m[1]}`;
    }

    return dateStr;
}

